    58â†’static void test_representative_100(void)
    59â†’{
    60â†’    /* --- Section 1: Special IEEE 754 values (7) --- */
    61â†’    emit(0.0);
    62â†’    emit(-0.0);
    63â†’    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    64â†’    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    65â†’    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    66â†’    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    67â†’    emit_u(0xfff0000000000000ULL);  /* -Inf */
    68â†’
    69â†’    /* --- Section 2: Subnormal (denormal) values (6) --- */
    70â†’    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    71â†’    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    72â†’    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    73â†’    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    74â†’    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    75â†’    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    76â†’
    77â†’    /* --- Section 3: Normal boundary values (4) --- */
    78â†’    emit(DBL_MIN);                  /* 2^-1022, smallest positive normal */
    79â†’    emit(-DBL_MIN);
    80â†’    emit(DBL_MAX);                  /* largest finite double */
    81â†’    emit(-DBL_MAX);
    82â†’
    83â†’    /* --- Section 4: Near 1.0 ULP density (8) --- */
    84â†’    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    85â†’    emit(1.0);
    86â†’    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    87â†’    emit_u(0x3feffffffffffffeULL);  /* two ULPs below 1.0 */
    88â†’    emit_u(0x3ff0000000000002ULL);  /* two ULPs above 1.0 */
    89â†’    emit(-1.0);
    90â†’    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    91â†’    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */
    92â†’
    93â†’    /* --- Section 5: Half-integer values (12) --- */
    94â†’    /* trunc(n+0.5) = n, trunc(-(n+0.5)) = -n */
    95â†’    emit(0.5);
    96â†’    emit(-0.5);
    97â†’    emit(1.5);
    98â†’    emit(-1.5);
    99â†’    emit(2.5);
   100â†’    emit(-2.5);
   101â†’    emit(3.5);
   102â†’    emit(-3.5);
   103â†’    emit(4.5);
   104â†’    emit(-4.5);
   105â†’    emit(100.5);
   106â†’    emit(-100.5);
   107â†’
   108â†’    /* --- Section 6: Small fractional values in (0,1) and (-1,0) (10) --- */
   109â†’    /* All should truncate to +/-0.0 */
   110â†’    emit(0.1);
   111â†’    emit(0.25);
   112â†’    emit(0.3);
   113â†’    emit(0.49999999999999994);       /* just below 0.5 */
   114â†’    emit(0.9999999999999998);        /* just below 1.0 */
   115â†’    emit(-0.1);
   116â†’    emit(-0.25);
   117â†’    emit(-0.3);
   118â†’    emit(-0.49999999999999994);      /* just above -0.5 */
   119â†’    emit(-0.9999999999999998);       /* just above -1.0 */
   120â†’
   121â†’    /* --- Section 7: Small integer values +/- (8) --- */
   122â†’    /* trunc of exact integers should return the input unchanged */
   123â†’    emit(2.0);
   124â†’    emit(-2.0);
   125â†’    emit(3.0);
   126â†’    emit(-3.0);
   127â†’    emit(5.0);
   128â†’    emit(-5.0);
   129â†’    emit(10.0);
   130â†’    emit(-10.0);
   131â†’
   132â†’    /* --- Section 8: Near-integer ULP boundaries (15) --- */
   133â†’    /* 1 ULP below n.0, exact n.0 (already covered), 1 ULP above n.0 */
   134â†’    /* n=2: 2.0 = 0x4000000000000000 */
   135â†’    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 (= largest value < 2) */
   136â†’    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */
   137â†’    /* n=3: 3.0 = 0x4008000000000000 */
   138â†’    emit_u(0x4007ffffffffffffULL);  /* one ULP below 3.0 */
   139â†’    emit_u(0x4008000000000001ULL);  /* one ULP above 3.0 */
   140â†’    /* n=4: 4.0 = 0x4010000000000000 */
   141â†’    emit_u(0x400fffffffffffffULL);  /* one ULP below 4.0 */
   142â†’    emit_u(0x4010000000000001ULL);  /* one ULP above 4.0 */
   143â†’    /* n=8: 8.0 = 0x4020000000000000 */
   144â†’    emit_u(0x401fffffffffffffULL);  /* one ULP below 8.0 */
   145â†’    emit_u(0x4020000000000001ULL);  /* one ULP above 8.0 */
   146â†’    /* n=16: 16.0 = 0x4030000000000000 */
   147â†’    emit_u(0x402fffffffffffffULL);  /* one ULP below 16.0 */
   148â†’    emit_u(0x4030000000000001ULL);  /* one ULP above 16.0 */
   149â†’    /* n=-2 */
   150â†’    emit_u(0xbfffffffffffffffULL);  /* one ULP toward zero from -2.0 */
   151â†’    emit_u(0xc000000000000001ULL);  /* one ULP away from zero from -2.0 */
   152â†’    /* n=-4 */
   153â†’    emit_u(0xc00fffffffffffffULL);  /* one ULP toward zero from -4.0 */
   154â†’    emit_u(0xc010000000000001ULL);  /* one ULP away from zero from -4.0 */
   155â†’    /* n=-8 */
   156â†’    emit_u(0xc01fffffffffffffULL);  /* one ULP toward zero from -8.0 */
   157â†’
   158â†’    /* --- Section 9: Large values where double loses fractional bits (15) --- */
   159â†’    /* At 2^52, the ULP is 1.0 so all values are integers; trunc is identity */
   160â†’    emit_u(0x4330000000000000ULL);  /* 2^52 = 4503599627370496.0 */
   161â†’    emit_u(0x4330000000000001ULL);  /* 2^52 + 1 */
   162â†’    emit_u(0x433fffffffffffffULL);  /* just below 2^53 */
   163â†’    emit_u(0x4340000000000000ULL);  /* 2^53 = 9007199254740992.0 */
   164â†’    emit_u(0x4340000000000001ULL);  /* 2^53 + 1 (ULP = 2 now) */
   165â†’    emit_u(0xc330000000000000ULL);  /* -2^52 */
   166â†’    emit_u(0xc340000000000000ULL);  /* -2^53 */
   167â†’    emit(1.0e15);                   /* large but representable integer */
   168â†’    emit(-1.0e15);
   169â†’    emit(1.0e16);
   170â†’    emit(-1.0e16);
   171â†’    emit(1.0e100);                  /* astronomically large */
   172â†’    emit(-1.0e100);
   173â†’    emit(1.0e300);
   174â†’    emit(-1.0e300);
   175â†’
   176â†’    /* --- Section 10: Mixed fractional cases across ranges (15) --- */
   177â†’    /* Values with fractional parts at various magnitudes */
   178â†’    emit(1.1);
   179â†’    emit(-1.1);
   180â†’    emit(1.9);
   181â†’    emit(-1.9);
   182â†’    emit(7.7);
   183â†’    emit(-7.7);
   184â†’    emit(127.999);
   185â†’    emit(-127.999);
   186â†’    emit(1000.0001);
   187â†’    emit(-1000.0001);
   188â†’    emit(1048576.5);                /* 2^20 + 0.5 */
   189â†’    emit(-1048576.5);               /* -(2^20 + 0.5) */
   190â†’    emit(2097151.9999999998);       /* just below 2^21 */
   191â†’    emit(4503599627370495.5);       /* 2^52 - 0.5: last representable non-integer */
   192â†’    emit(-4503599627370495.5);      /* -(2^52 - 0.5) */
   193â†’}
