   197â†’#ifndef EN_PERF
   198â†’/* Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
   199â†’static void test_sweep(void)
   200â†’{
   201â†’    double hi = 10.0;
   202â†’    int nsteps = 100;
   203â†’    double step = hi / (double)nsteps;
   204â†’
   205â†’    /* [0, 10] */
